const reglas = $('Query Métricas Reglas 3 Meses').all().map(i => i.json);
const globales = $('Query Métricas Globales Agente').first().json;

const FP_THRESHOLD = 0.40;  // 40% FP → subir umbral
const TP_THRESHOLD = 0.30;  // <30% TP con pocas activaciones → revisar si la regla detecta algo
const MIN_CASOS = 5;        // mínimo de casos para proponer cambio

const propuestas = [];

for (const regla of reglas) {
  const fp3m = Number(regla.fp_rate_3m || 0);
  const casos = Number(regla.casos_3m || 0);
  const tp3m = Number(regla.tp_3m || 0);
  const fp_n = Number(regla.fp_3m || 0);

  if (casos < MIN_CASOS) continue; // no suficientes datos

  let propuesta = null;

  // Regla con exceso de falsos positivos: subir umbral
  if (fp3m >= FP_THRESHOLD) {
    if (regla.umbral_pct_min !== null) {
      const nuevoUmbral = Math.round((Number(regla.umbral_pct_min) * 1.3) * 10) / 10; // +30%
      propuesta = {
        codigo_regla: regla.codigo_regla,
        nombre: regla.nombre,
        tipo: 'subir_umbral',
        descripcion: `FP rate ${(fp3m*100).toFixed(0)}% (${fp_n}/${casos} casos). Propuesta: subir umbral de ${regla.umbral_pct_min}% a ${nuevoUmbral}%`,
        campo: 'umbral_pct_min',
        valor_actual: regla.umbral_pct_min,
        valor_propuesto: nuevoUmbral,
        fp_rate_actual: fp3m,
        justificacion: `Demasiados falsos positivos (${(fp3m*100).toFixed(0)}%) reducen la confianza del analista. Subir el umbral filtrará ruido sin sacrificar alertas útiles.`
      };
    } else if (regla.umbral_zscore !== null) {
      const nuevoZ = Math.round((Number(regla.umbral_zscore) + 0.5) * 10) / 10;
      propuesta = {
        codigo_regla: regla.codigo_regla,
        nombre: regla.nombre,
        tipo: 'subir_zscore',
        descripcion: `FP rate ${(fp3m*100).toFixed(0)}%. Propuesta: subir z-score de ${regla.umbral_zscore} a ${nuevoZ}`,
        campo: 'umbral_zscore',
        valor_actual: regla.umbral_zscore,
        valor_propuesto: nuevoZ,
        fp_rate_actual: fp3m,
        justificacion: `Z-score actual demasiado bajo, captura variaciones normales. Subir a ${nuevoZ} focalizará en anomalías más claras.`
      };
    }
  }
  // Regla útil con FP bajo: confirmar que está bien
  else if (fp3m < 0.10 && casos >= 10 && tp3m >= 3) {
    propuesta = {
      codigo_regla: regla.codigo_regla,
      nombre: regla.nombre,
      tipo: 'confirmar_umbral',
      descripcion: `Regla funcionando bien: ${(fp3m*100).toFixed(0)}% FP, ${tp3m} alertas confirmadas en 3 meses.`,
      campo: null,
      valor_actual: regla.umbral_pct_min || regla.umbral_zscore,
      valor_propuesto: null,
      fp_rate_actual: fp3m,
      justificacion: 'Mantener umbral actual. Regla tiene buena precisión.'
    };
  }

  if (propuesta) propuestas.push(propuesta);
}

// Métricas globales para el reporte
const mae = Number(globales.mae_forecast_pct || 0);
const cobertura = Number(globales.cobertura_alertas_utiles || 0);
const tiempoMediano = Number(globales.tiempo_mediano_alta_critica_h || 0);
const ahorro3m = Number(globales.ahorro_3m || 0);
const precisionIA = Number(globales.precision_ia || 0);

return [{
  json: {
    propuestas,
    n_propuestas: propuestas.length,
    propuestas_cambio: propuestas.filter(p => p.tipo !== 'confirmar_umbral'),
    metricas_globales: {
      mae_forecast_pct: Math.round(mae * 100) / 100,
      cobertura_alertas_utiles: Math.round(cobertura * 100),
      tiempo_mediano_horas: Math.round(tiempoMediano * 10) / 10,
      ahorro_3m: Math.round(ahorro3m),
      precision_ia_pct: Math.round(precisionIA * 100)
    },
    // KPIs vs metas
    kpis_ok: {
      mae_ok: mae <= 3.0,
      cobertura_ok: cobertura >= 0.60,
      tiempo_ok: tiempoMediano <= 48,
      precision_ok: precisionIA >= 0.80
    }
  }
}];

const data = $input.first().json;
const m = data.metricas_globales;
const kpis = data.kpis_ok;

const ico = (ok) => ok ? '✅' : '⚠️';
const fmt = (n) => n ? `$${Number(n).toLocaleString('es-CO')}` : '$0';

// Resumen de métricas
const metricas = [
  `${ico(kpis.mae_ok)} MAE forecast: *${m.mae_forecast_pct}%* (meta ≤3%)`,
  `${ico(kpis.cobertura_ok)} Cobertura alertas útiles: *${m.cobertura_alertas_utiles}%* (meta ≥60%)`,
  `${ico(kpis.tiempo_ok)} Tiempo mediano cierre alertas altas: *${m.tiempo_mediano_horas}h* (meta ≤48h)`,
  `${ico(kpis.precision_ok)} Precisión clasificación IA: *${m.precision_ia_pct}%* (meta ≥80%)`,
  `💰 Ahorro detectado 3 meses: *${fmt(m.ahorro_3m)}*`
].join('\n');

// Propuestas de cambio
const propuestasCambio = data.propuestas_cambio || [];
const propuestasTexto = propuestasCambio.length > 0
  ? propuestasCambio.map((p, i) =>
    `*${i+1}. ${p.codigo_regla} — ${p.nombre}*\n${p.descripcion}\n_${p.justificacion}_`
  ).join('\n\n')
  : 'Ninguna regla requiere ajuste de umbral este mes.';

return [{
  json: {
    ...data,
    texto_metricas: metricas,
    texto_propuestas: propuestasTexto,
    hay_cambios: propuestasCambio.length > 0
  }
}];

// Preparar los UPDATE SQL para cada propuesta de cambio
// Estos se ejecutan solo si el analista aprueba via Slack
const propuestas = $input.first().json.propuestas_cambio || [];

const queries = propuestas
  .filter(p => p.campo && p.valor_propuesto !== null)
  .map(p => (
    `UPDATE opex_rules SET ${p.campo} = ${p.valor_propuesto}, version = version + 1, effective_from = CURRENT_DATE, modificado_en = NOW(), modificado_por = 'wf_09_recalibracion' WHERE codigo_regla = '${p.codigo_regla}' AND activa = true;`
  ));

return [{ json: { queries, n_queries: queries.length, propuestas } }];
